def find_tail_patterns(text):
    # Find tail-call patterns
    patterns = re.findall(r'[a-zA-Z_$]+:while\(true\)\{[^{}]*(?:\{[^{}]*\}[^{}]*)*\}', text)
    return patterns

def extract_from_test_output():
    lines = test_output.strip().split('\n')

    expected_line = None
    for line in lines:
        if line.strip().startswith('expected:'):
            expected_line = line
            break

    if not expected_line:
        print("Could not find expected line in test output")
        return None, None

    # Extract the JavaScript code from the expected line
    start = expected_line.find('"') + 1
    end = expected_line.rfind('"')
    expected_js = expected_line[start:end]

    # For this analysis, let's look at the actual vs expected from test files
    try:
        with open('/tmp/debug-canopy-user-basic-arithmetic.js', 'r') as f:
            canopy_js = f.read()
    except FileNotFoundError:
        print("Debug file not found")
        return None, None

    return expected_js, canopy_js

def main():
    expected_js, canopy_js = extract_from_test_output()

    if expected_js and canopy_js:
        print("=== TAIL-CALL PATTERNS COMPARISON ===")

        elm_patterns = find_tail_patterns(expected_js)
        canopy_patterns = find_tail_patterns(canopy_js)

        print(f"\nElm patterns found: {len(elm_patterns)}")
        for i, pattern in enumerate(elm_patterns):
            print(f"  {i+1}: {pattern[:150]}...")

        print(f"\nCanopy patterns found: {len(canopy_patterns)}")
        for i, pattern in enumerate(canopy_patterns):
            print(f"  {i+1}: {pattern[:150]}...")

        # Show specific differences in foldr function
        elm_foldr = re.search(r'function \$elm\$core\$Dict\$foldr.*?foldr:while\(true\)\{.*?\}', expected_js, re.DOTALL)
        canopy_foldr = re.search(r'function \$elm\$core\$Dict\$foldr.*?foldr:while\(true\)\{.*?\}', canopy_js, re.DOTALL)

        if elm_foldr and canopy_foldr:
            print(f"\n=== ELM FOLDR ===")
            print(elm_foldr.group(0)[:300] + "...")
            print(f"\n=== CANOPY FOLDR ===")
            print(canopy_foldr.group(0)[:300] + "...")

if __name__ == "__main__":
    main()